parameters.jsCode:
const body = $input.item.json.body || $input.item.json;

const name = String(body.name || '').trim();
const email = String(body.email || '').trim();
const subject = String(body.subject || '').trim();
const message = String(body.message || '').trim();
const source = String(body.source || 'webhook').trim();

const emailValid = /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);

let completeness = 0;
if (name) completeness += 20;
if (emailValid) completeness += 20;
if (subject.length >= 3) completeness += 20;
if (message.length >= 10) completeness += 30;
if (source) completeness += 10;

return [{
  json: {
    name: name || 'Unknown',
    email: emailValid ? email : 'invalid',
    subject: subject || 'No Subject',
    message: message || 'No details provided',
    source: source,
    completeness: completeness,
    timestamp: new Date().toISOString()
  }
}];

